<?php
namespace App\Filament\Resources;
use App\Filament\Resources\UserResource\Pages;use App\Models\User;use Filament\Actions\EditAction;use Filament\Forms\Components\TextInput;use Filament\Forms\Components\Toggle;use Filament\Resources\Resource;use Filament\Schemas\Schema;use Filament\Tables\Columns\IconColumn;use Filament\Tables\Columns\TextColumn;use Filament\Tables\Table;use Illuminate\Support\Facades\Hash;
class UserResource extends Resource{protected static ?string $model=User::class;protected static ?string $navigationLabel='ადმინისტრატორები';public static function form(Schema $schema):Schema{return $schema->components([TextInput::make('name')->required(),TextInput::make('email')->email()->required()->unique(ignoreRecord:true),TextInput::make('password')->password()->revealable()->required(fn(string $operation)=>$operation==='create')->dehydrated(fn(?string $state)=>filled($state))->dehydrateStateUsing(fn(string $state)=>Hash::make($state)),Toggle::make('is_admin')->label('Admin წვდომა')->default(true)]);}public static function table(Table $table):Table{return $table->columns([TextColumn::make('name')->searchable(),TextColumn::make('email')->searchable(),IconColumn::make('is_admin')->boolean(),TextColumn::make('created_at')->dateTime()])->recordActions([EditAction::make()]);}public static function getPages():array{return ['index'=>Pages\ListUsers::route('/'),'create'=>Pages\CreateUser::route('/create'),'edit'=>Pages\EditUser::route('/{record}/edit')];}}
